function solve(nums, queries) {
    const n = nums.length;
    const ans = [];

    // Preprocess the array to create a list of lists, where each sublist contains the counts of elements from index i to the end
    // This is done using a suffix array approach
    const suffixCounts = Array(n).fill().map(() => new Map());
    for (let i = n - 1; i >= 0; i--) {
        const currentNum = nums[i];
        if (i < n - 1) {
            for (const [key, value] of suffixCounts[i + 1].entries()) {
                suffixCounts[i].set(key, value);
            }
        }
        suffixCounts[i].set(currentNum, (suffixCounts[i].get(currentNum) || 0) + 1);
    }

    for (const [l, r, threshold] of queries) {
        // Get the frequency map for the subarray nums[l...r]
        const freq = new Map();
        for (let i = l; i <= r; i++) {
            const num = nums[i];
            freq.set(num, (freq.get(num) || 0) + 1);
        }

        // Find the element with at least threshold occurrences
        let maxFreq = -1;
        let result = -1;
        for (const [num, count] of freq.entries()) {
            if (count >= threshold) {
                if (count > maxFreq || (count === maxFreq && num < result)) {
                    maxFreq = count;
                    result = num;
                }
            }
        }

        ans.push(result);
    }

    return ans;
}
